  "Archived notification": { fr: "Notification archivée", es: "Notificación archivada", pt: "Notificação arquivada", ar: "إشعار مؤرشَف", de: "Archivierte Benachrichtigung", it: "Notifica archiviata", zh: "已归档通知", hi: "संग्रहीत सूचना", ig: "Ọkwa edebere", yo: "Ìfòfófó tí a fi pamọ́", ha: "Sanarwa da aka adana" },
