  "Copy thread ID": { fr: "Copier l'ID du fil", es: "Copiar ID del hilo", pt: "Copiar ID do tópico", ar: "نسخ معرّف المحادثة", de: "Thread-ID kopieren", it: "Copia ID conversazione", zh: "复制会话 ID", hi: "थ्रेड ID कॉपी करें", ig: "Detuo ID eriri", yo: "Daakọ ID òwò", ha: "Kwafa ID na zaren" },
  "Copy thread link": { fr: "Copier le lien du fil", es: "Copiar enlace del hilo", pt: "Copiar link do tópico", ar: "نسخ رابط المحادثة", de: "Thread-Link kopieren", it: "Copia link della conversazione", zh: "复制会话链接", hi: "थ्रेड लिंक कॉपी करें", ig: "Detuo njikọ eriri", yo: "Daakọ àsopọ̀ òwò", ha: "Kwafa hanyar zaren" },
  "Couldn't save the address. Please try again.": { fr: "Impossible d'enregistrer l'adresse. Veuillez réessayer.", es: "No se pudo guardar la dirección. Inténtalo de nuevo.", pt: "Não foi possível guardar o endereço. Por favor, tenta novamente.", ar: "تعذّر حفظ العنوان. يُرجى المحاولة مرة أخرى.", de: "Adresse konnte nicht gespeichert werden. Bitte erneut versuchen.", it: "Impossibile salvare l'indirizzo. Riprova.", zh: "无法保存地址,请重试。", hi: "पता सहेजा नहीं जा सका। पुनः प्रयास करें।", ig: "Enweghị ike ịchekwa adreesị. Biko nwaa ọzọ.", yo: "A kò lè pa àdírẹ́sì mọ́. Jọ̀wọ́ tún gbìyànjú.", ha: "Ba a iya adana adireshin ba. Da fatan za a sake gwadawa." },
  "Couldn't submit the report. Try again.": { fr: "Impossible d'envoyer le rapport. Réessayez.", es: "No se pudo enviar el reporte. Inténtalo de nuevo.", pt: "Não foi possível submeter o relatório. Tenta novamente.", ar: "تعذّر إرسال البلاغ. حاول مرة أخرى.", de: "Bericht konnte nicht gesendet werden. Erneut versuchen.", it: "Impossibile inviare il report. Riprova.", zh: "无法提交报告,请重试。", hi: "रिपोर्ट सबमिट नहीं हो सकी। पुनः प्रयास करें।", ig: "Enweghị ike inyefe akụkọ. Nwaa ọzọ.", yo: "A kò lè fi ìròyìn ránṣẹ́. Tún gbìyànjú.", ha: "Ba a iya gabatar da rahoto ba. Sake gwadawa." },
  "Couldn't update mute. Try again.": { fr: "Impossible de mettre à jour le silence. Réessayez.", es: "No se pudo actualizar el silencio. Inténtalo de nuevo.", pt: "Não foi possível atualizar o silêncio. Tenta novamente.", ar: "تعذّر تحديث الكتم. حاول مرة أخرى.", de: "Stummschaltung konnte nicht aktualisiert werden. Erneut versuchen.", it: "Impossibile aggiornare il silenziamento. Riprova.", zh: "无法更新静音,请重试。", hi: "म्यूट अपडेट नहीं हो सका। पुनः प्रयास करें।", ig: "Enweghị ike imelite olu ịda ụda. Nwaa ọzọ.", yo: "A kò lè ṣe àtúnṣe pípa mọ́. Tún gbìyànjú.", ha: "Ba a iya sabunta kashe sauti ba. Sake gwadawa." },
  "Couldn't update the address. Please try again.": { fr: "Impossible de mettre à jour l'adresse. Veuillez réessayer.", es: "No se pudo actualizar la dirección. Inténtalo de nuevo.", pt: "Não foi possível atualizar o endereço. Por favor, tenta novamente.", ar: "تعذّر تحديث العنوان. يُرجى المحاولة مرة أخرى.", de: "Adresse konnte nicht aktualisiert werden. Bitte erneut versuchen.", it: "Impossibile aggiornare l'indirizzo. Riprova.", zh: "无法更新地址,请重试。", hi: "पता अपडेट नहीं हो सका। पुनः प्रयास करें।", ig: "Enweghị ike imelite adreesị. Biko nwaa ọzọ.", yo: "A kò lè ṣe àtúnṣe àdírẹ́sì. Jọ̀wọ́ tún gbìyànjú.", ha: "Ba a iya sabunta adireshi ba. Da fatan za a sake gwadawa." },
  "Country, language, timezone pending": { fr: "Pays, langue, fuseau horaire en attente", es: "País, idioma, zona horaria pendientes", pt: "País, idioma, fuso horário pendentes", ar: "الدولة واللغة والمنطقة الزمنية قيد الانتظار", de: "Land, Sprache, Zeitzone ausstehend", it: "Paese, lingua, fuso orario in sospeso", zh: "国家、语言、时区待定", hi: "देश, भाषा, टाइमज़ोन लंबित", ig: "Obodo, asụsụ, oge ebe na-echere", yo: "Orílẹ̀-èdè, èdè, ìpínlẹ̀ àkókò dúró", ha: "Ƙasa, harshe, yankin lokaci a jira" },
  "Course activity, progress, and certification updates": { fr: "Activité de cours, progression et mises à jour de certification", es: "Actividad del curso, progreso y actualizaciones de certificación", pt: "Atividade de curso, progresso e atualizações de certificação", ar: "نشاط الدورة والتقدّم وتحديثات الشهادات", de: "Kurs-Aktivität, Fortschritt und Zertifizierungs-Updates", it: "Attività del corso, progresso e aggiornamenti certificazione", zh: "课程活动、进度与认证更新", hi: "कोर्स गतिविधि, प्रगति और प्रमाणन अपडेट", ig: "Omume nkuzi, ọganihu na mmelite asambodo", yo: "Ìṣe ìdánilẹ́kọ̀ọ́, ìlọsíwájú, àti ìmúdátọ́jú ẹ̀rí", ha: "Ayyukan kwas, ci gaba, da sabuntawar takardar shaida" },
  "Credential": { fr: "Identifiant", es: "Credencial", pt: "Credencial", ar: "اعتماد", de: "Credential", it: "Credenziale", zh: "凭证", hi: "क्रेडेंशियल", ig: "Akaebe", yo: "Ẹ̀rí", ha: "Takardar shaida" },
